// src/pages/GroupDetails.jsx
import { useParams, useNavigate } from 'react-router-dom';
import { useEffect, useState } from 'react';

export default function GroupDetails() {
  const { groupId } = useParams();
  const navigate = useNavigate();
  const [group, setGroup] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Simule un fetch depuis un tableau local ou un service
    const localGroups = JSON.parse(localStorage.getItem('groups')) || [];

    const foundGroup = localGroups.find(g => String(g.id) === groupId);
    if (foundGroup) {
      setGroup(foundGroup);
    } else {
      // Redirection si l'ID ne correspond à rien
      navigate('/not-found');
    }

    setLoading(false);
  }, [groupId, navigate]);

  if (loading) {
    return <div>Chargement...</div>;
  }

  return (
    <div className="p-8">
      <h1 className="text-3xl font-bold mb-4">{group.name}</h1>
      {/* Détails du groupe */}
    </div>
  );
}
